// app/dashboard/page.tsx - UPDATED WITH MODE SUPPORT
'use client';
import { useState, useEffect } from 'react';
import Link from 'next/link';
import { Plus, Eye, Edit, Trash2, Calendar, User, Loader2, Settings, Users } from 'lucide-react';
import { supabase, Memorial } from '@/lib/supabase';

export default function DashboardPage() {
  const [memorials, setMemorials] = useState<Memorial[]>([]);
  const [loading, setLoading] = useState(true);
  const [filter, setFilter] = useState<'all' | 'draft' | 'published'>('all');
  const [mode, setMode] = useState<'personal' | 'family'>('family');
  const [showModeSelector, setShowModeSelector] = useState(false);

  useEffect(() => {
    // Load mode from localStorage
    const savedMode = localStorage.getItem('legacy-vault-mode') as 'personal' | 'family' | null;
    if (savedMode) {
      setMode(savedMode);
    } else {
      // If no mode is set, redirect to choice page
      window.location.href = '/choice';
    }

    loadMemorials();
  }, [filter]);

  const loadMemorials = async () => {
    setLoading(true);
    try {
      let query = supabase
        .from('memorials')
        .select('*')
        .order('updated_at', { ascending: false });

      if (filter !== 'all') {
        query = query.eq('status', filter);
      }

      const { data, error } = await query;
      if (error) throw error;
      setMemorials(data || []);
    } catch (error) {
      console.error('Error loading memorials:', error);
    } finally {
      setLoading(false);
    }
  };

  const deleteMemorial = async (id: string, name: string) => {
    if (!confirm(`Are you sure you want to delete "${name}"?`)) return;

    try {
      const { error } = await supabase
        .from('memorials')
        .delete()
        .eq('id', id);

      if (error) throw error;
      loadMemorials();
    } catch (error) {
      console.error('Error deleting memorial:', error);
      alert('Failed to delete memorial');
    }
  };

  const formatDate = (dateString: string) => {
    return new Date(dateString).toLocaleDateString('en-US', {
      month: 'short',
      day: 'numeric',
      year: 'numeric',
    });
  };

  const handleCreateNewMemorial = () => {
    // Check if in Personal mode and already has a memorial
    if (mode === 'personal' && memorials.length >= 1) {
      alert('In Personal mode, you can only create one memorial archive. Please delete your existing memorial if you want to create a new one, or switch to Family mode.');
      return;
    }

    // Clear the tutorial completion flag so it shows again
    localStorage.removeItem('legacy-vault-tutorial-completed');
    // Navigate to create page
    window.location.href = '/create';
  };

  const handleModeChange = (newMode: 'personal' | 'family') => {
    // If switching to Personal mode and has more than 1 memorial, warn user
    if (newMode === 'personal' && memorials.length > 1) {
      if (!confirm('Switching to Personal mode will restrict you to one memorial. You currently have ' + memorials.length + ' memorials. Continue?')) {
        return;
      }
    }

    localStorage.setItem('legacy-vault-mode', newMode);
    setMode(newMode);
    setShowModeSelector(false);
  };

  const canCreateMemorial = mode === 'family' || memorials.length === 0;

  return (
    <div className="min-h-screen bg-gradient-to-br from-sage/5 via-ivory to-terracotta/5">
      {/* Header */}
      <div className="bg-white border-b border-sand/30 shadow-sm">
        <div className="max-w-7xl mx-auto px-6 py-6">
          <div className="flex items-center justify-between">
            <div>
              <div className="flex items-center gap-3 mb-2">
                <h1 className="font-serif text-4xl text-charcoal">Memorial Dashboard</h1>
                {/* Mode Badge */}
                <button
                  onClick={() => setShowModeSelector(!showModeSelector)}
                  className={`px-3 py-1 rounded-full text-xs font-medium flex items-center gap-1.5 transition-all hover:scale-105 ${mode === 'personal'
                    ? 'bg-sage/10 text-sage border border-sage/30'
                    : 'bg-terracotta/10 text-terracotta border border-terracotta/30'
                    }`}
                >
                  {mode === 'personal' ? <User size={12} /> : <Users size={12} />}
                  {mode === 'personal' ? 'Personal' : 'Family'} Mode
                  <Settings size={12} />
                </button>
              </div>
              <p className="text-charcoal/60">
                {mode === 'personal'
                  ? 'Your personal memorial archive'
                  : 'Manage all your family memorials in one place'
                }
              </p>
            </div>

            {/* Mode Selector Dropdown */}
            {showModeSelector && (
              <div className="absolute top-20 left-6 bg-white border-2 border-sand/30 rounded-xl shadow-xl p-4 z-50 animate-fadeIn">
                <p className="text-xs font-medium text-charcoal/60 mb-3">Switch Mode</p>
                <div className="space-y-2">
                  <button
                    onClick={() => handleModeChange('personal')}
                    className={`w-full px-4 py-2 rounded-lg text-left flex items-center gap-2 text-sm transition-all ${mode === 'personal'
                      ? 'bg-sage/10 text-sage font-medium'
                      : 'hover:bg-sand/10 text-charcoal'
                      }`}
                  >
                    <User size={16} />
                    Personal (1 memorial max)
                  </button>
                  <button
                    onClick={() => handleModeChange('family')}
                    className={`w-full px-4 py-2 rounded-lg text-left flex items-center gap-2 text-sm transition-all ${mode === 'family'
                      ? 'bg-terracotta/10 text-terracotta font-medium'
                      : 'hover:bg-sand/10 text-charcoal'
                      }`}
                  >
                    <Users size={16} />
                    Family (unlimited)
                  </button>
                </div>
              </div>
            )}

            {/* Create Button */}
            <button
              onClick={handleCreateNewMemorial}
              disabled={!canCreateMemorial}
              className={`px-6 py-3 rounded-xl font-semibold transition-all flex items-center gap-2 ${canCreateMemorial
                ? 'bg-gradient-to-r from-sage to-sage/90 hover:shadow-lg text-ivory'
                : 'bg-sand/30 text-charcoal/40 cursor-not-allowed'
                }`}
            >
              <Plus size={20} />
              Create New Memorial
            </button>
          </div>

          {/* Personal Mode Warning */}
          {mode === 'personal' && memorials.length >= 1 && (
            <div className="mt-4 p-3 bg-sage/10 border border-sage/30 rounded-lg">
              <p className="text-xs text-charcoal/70">
                <strong>Personal Mode:</strong> You've reached your memorial limit (1). Delete your existing memorial or switch to Family mode to create more.
              </p>
            </div>
          )}
        </div>
      </div>

      <div className="max-w-7xl mx-auto px-6 py-12">
        {/* Filters */}
        <div className="mb-8 flex gap-3">
          <button
            onClick={() => setFilter('all')}
            className={`px-4 py-2 rounded-lg font-medium transition-all ${filter === 'all'
              ? 'bg-sage text-ivory'
              : 'bg-white border border-sand/40 text-charcoal hover:bg-sand/10'
              }`}
          >
            All ({memorials.length})
          </button>
          <button
            onClick={() => setFilter('published')}
            className={`px-4 py-2 rounded-lg font-medium transition-all ${filter === 'published'
              ? 'bg-sage text-ivory'
              : 'bg-white border border-sand/40 text-charcoal hover:bg-sand/10'
              }`}
          >
            Published
          </button>
          <button
            onClick={() => setFilter('draft')}
            className={`px-4 py-2 rounded-lg font-medium transition-all ${filter === 'draft'
              ? 'bg-sage text-ivory'
              : 'bg-white border border-sand/40 text-charcoal hover:bg-sand/10'
              }`}
          >
            Drafts
          </button>
        </div>

        {/* Loading State */}
        {loading ? (
          <div className="flex items-center justify-center py-20">
            <div className="text-center">
              <Loader2 size={48} className="text-sage animate-spin mx-auto mb-4" />
              <p className="text-charcoal/60">Loading memorials...</p>
            </div>
          </div>
        ) : memorials.length === 0 ? (
          /* Empty State */
          <div className="text-center py-20">
            <div className="w-24 h-24 bg-sand/20 rounded-full flex items-center justify-center mx-auto mb-6">
              <User size={48} className="text-charcoal/30" />
            </div>
            <h2 className="font-serif text-3xl text-charcoal mb-3">
              {mode === 'personal' ? 'Create Your Memorial' : 'No memorials yet'}
            </h2>
            <p className="text-charcoal/60 mb-8">
              {mode === 'personal'
                ? 'Start preserving your personal legacy'
                : 'Create your first memorial to get started'
              }
            </p>
            <button
              onClick={handleCreateNewMemorial}
              className="inline-flex items-center gap-2 px-6 py-3 bg-sage hover:bg-sage/90 text-ivory rounded-xl font-semibold transition-all"
            >
              <Plus size={20} />
              {mode === 'personal' ? 'Create My Memorial' : 'Create Your First Memorial'}
            </button>
          </div>
        ) : (
          /* Memorial Grid */
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
            {memorials.map((memorial) => (
              <div
                key={memorial.id}
                className="bg-white rounded-xl shadow-sm border border-sand/30 overflow-hidden hover:shadow-lg transition-all group"
              >
                {/* Cover/Profile Photo */}
                <div className="relative h-48 bg-gradient-to-br from-sage/10 to-terracotta/10">
                  {memorial.cover_photo_url ? (
                    <img
                      src={memorial.cover_photo_url}
                      alt={memorial.full_name || 'Memorial'}
                      className="w-full h-full object-cover"
                    />
                  ) : memorial.profile_photo_url ? (
                    <img
                      src={memorial.profile_photo_url}
                      alt={memorial.full_name || 'Memorial'}
                      className="w-full h-full object-cover"
                    />
                  ) : (
                    <div className="w-full h-full flex items-center justify-center">
                      <User size={64} className="text-charcoal/20" />
                    </div>
                  )}
                  {/* Status Badge */}
                  <div className="absolute top-3 right-3">
                    <span
                      className={`px-3 py-1 rounded-full text-xs font-medium ${memorial.status === 'published'
                        ? 'bg-sage/90 text-ivory'
                        : 'bg-sand/90 text-charcoal'
                        }`}
                    >
                      {memorial.status === 'published' ? '✓ Published' : 'Draft'}
                    </span>
                  </div>
                </div>

                {/* Content */}
                <div className="p-6">
                  <h3 className="font-serif text-2xl text-charcoal mb-2 line-clamp-1">
                    {memorial.full_name || 'Untitled Memorial'}
                  </h3>
                  {(memorial.birth_date || memorial.death_date) && (
                    <div className="flex items-center gap-2 text-sm text-charcoal/60 mb-4">
                      <Calendar size={14} />
                      <span>
                        {memorial.birth_date ? new Date(memorial.birth_date).getFullYear() : '?'}
                        {' - '}
                        {memorial.death_date ? new Date(memorial.death_date).getFullYear() : 'Present'}
                      </span>
                    </div>
                  )}
                  <div className="text-xs text-charcoal/40 mb-4">
                    Updated {formatDate(memorial.updated_at)}
                  </div>

                  {/* Action Buttons */}
                  <div className="flex gap-2">
                    <Link
                      href={`/person/${memorial.id}`}
                      className="flex-1 py-2 px-3 bg-sage/10 hover:bg-sage/20 text-sage rounded-lg font-medium transition-all flex items-center justify-center gap-2 text-sm"
                    >
                      <Eye size={16} />
                      View
                    </Link>
                    <Link
                      href={`/create?id=${memorial.id}`}
                      className="flex-1 py-2 px-3 bg-terracotta/10 hover:bg-terracotta/20 text-terracotta rounded-lg font-medium transition-all flex items-center justify-center gap-2 text-sm"
                    >
                      <Edit size={16} />
                      Edit
                    </Link>
                    <button
                      onClick={() => deleteMemorial(memorial.id, memorial.full_name || 'this memorial')}
                      className="py-2 px-3 bg-red-50 hover:bg-red-100 text-red-600 rounded-lg font-medium transition-all flex items-center justify-center"
                    >
                      <Trash2 size={16} />
                    </button>
                  </div>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
}